SELECT FROM blog_category c LEFT JOIN blog_category_group g ON c.group_id = g.id AND g.deleted_at IS NULL WHERE c.deleted_at IS NULL
AND c.enabled = #{enabled}
AND g.enabled = 1
AND c.group_id = #{groupId}
AND ( c.name LIKE CONCAT('%', #{keyword}, '%') OR c.description LIKE CONCAT('%', #{keyword}, '%') OR g.name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY g.sort_order ASC, c.sort_order ASC, c.id ASC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM blog_category c LEFT JOIN blog_category_group g ON c.group_id = g.id AND g.deleted_at IS NULL WHERE c.deleted_at IS NULL
AND c.enabled = #{enabled}
AND g.enabled = 1
AND c.group_id = #{groupId}
AND ( c.name LIKE CONCAT('%', #{keyword}, '%') OR c.description LIKE CONCAT('%', #{keyword}, '%') OR g.name LIKE CONCAT('%', #{keyword}, '%') )

SELECT COUNT(1)
FROM blog_category
WHERE name = #{name}
AND deleted_at IS NULL

    AND id != #{excludeId}
